POLICY_VERSION = "v2.1"  # bump when policy changes

def cache_key(content: str) -> str:
    return hashlib.sha256(f"{POLICY_VERSION}:{content}".encode()).hexdigest()

def route_decision(decision: ModerationDecision) -> str:
    """Determine what action to take based on decision and confidence."""
    if decision.confidence >= 0.90:
        # High confidence: trust the model
        if decision.action == "remove":
            return "auto_remove"
        elif decision.action == "review":
            return "human_review"  # model says review → still review
        else:
            return "auto_allow"

    elif decision.confidence >= 0.70:
        # Medium confidence: always route to human
        return "human_review"

    else:
        # Low confidence: model unsure — favor allowing to avoid false positives
        return "auto_allow_with_monitoring"
